        "ranges": [
          {
            "from": "2020-09-01T00:00:00.000000+00:00"
          }
        ]
      }
    }
  },
  "query": {
    "bool": {
      "must": [
        {
          "terms": {
            "agent.id": []
          }
        }
      ]
    }
  }
}
```

